# 統合辞書
# ──────────────────────────────────────────────────────────────────────────────
TICKER_INFO: dict[str, dict] = {**_JP, **_US}

# スクリーナー対象: 全銘柄
SCREENER_TICKERS: list[str] = list(TICKER_INFO.keys())

# 注目銘柄（Discover）対象: featured=True の銘柄 + 流動性重視
DISCOVER_TICKERS: list[str] = [
    t for t, m in TICKER_INFO.items() if m.get("featured", False)
]

def get_info(ticker: str) -> dict:
    """メタデータを返す。未登録は空dict"""
    return TICKER_INFO.get(ticker, {})
